```java
import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums) {
        long[] absNums = new long[nums.length];
        for (int i = 0; i < nums.length; i++) {
            absNums[i] = Math.abs(nums[i]);
        }
        Arrays.sort(absNums);
        long total = 0;
        int n = nums.length;
        for (int i = 0; i < n; i++) {
            long target = 2 * absNums[i];
            int low = i + 1;
            int high = n - 1;
            int res = -1;
            while (low <= high) {
                int mid = (low + high) / 2;
                if (absNums[mid] <= target) {
                    res = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            if (res != -1) {
                total += res - i;
            }
        }
        return total;
    }
}
```

